  1→// Package fixture loads JSON fixture data into a PostgreSQL database.
  2→//
  3→// Fixture files are JSON arrays of objects (one file per table), optionally
  4→// xz-compressed. Files are named "<schema>.<table>.json" or
  5→// "<schema>.<table>.json.xz" and stored in a directory that is passed to
  6→// [Load] as an [io/fs.FS].
  7→//
  8→// Tables are loaded in FK-safe order. After all tables are populated, the
  9→// materialized views dataset_merged and dataset_latest are refreshed.
 10→package fixture
 11→
 12→import (
 13→	"bytes"
 14→	"context"
 15→	"encoding/json"
 16→	"fmt"
 17→	"io"
 18→	"io/fs"
 19→	"os/exec"
 20→	"strings"
 21→
 22→	"github.com/jackc/pgx/v5"
 23→	"github.com/jackc/pgx/v5/pgxpool"
 24→)
 25→
 26→// tableSpec defines a fixture table and how to load it.
 27→type tableSpec struct {
 28→	Schema string
 29→	Table  string
 30→}
 31→
 32→// loadOrder is the FK-safe order for loading fixture data. This must match
 33→// the extraction order in tools/samplesql/extractor.go.
 34→var loadOrder = []tableSpec{
 35→	{"location", "state"},
 36→	{"search_base", "ranking"},
 37→	{"search_base", "conference"},
 38→	{"search_base", "cip_data"},
 39→	{"search_base", "institution"},
 40→	{"search_base", "dataset"},
 41→	{"search_base", "annual_dataset"},
 42→	{"search_base", "institution_alias"},
 43→	{"location", "institution_normalized_alias"},
 44→	{"location", "zip_coordinates"},
 45→}
 46→
 47→// materializedViews are refreshed after all data is loaded.
 48→var materializedViews = []string{
 49→	"search_base.dataset_merged",
 50→	"search_base.dataset_latest",
 51→}
 52→
 53→// Load reads JSON fixture files from dataFS and inserts them into the database
 54→// in FK-safe order. The dataFS should contain files named
 55→// "<schema>.<table>.json" or "<schema>.<table>.json.xz".
 56→//
 57→// The database schema must already exist (migrations applied) before calling
 58→// Load.
 59→func Load(ctx context.Context, pool *pgxpool.Pool, dataFS fs.FS) error {
 60→	// Discover column types for geometry and JSONB detection.
 61→	colTypes, err := discoverColumnTypes(ctx, pool)
 62→	if err != nil {
 63→		return err
 64→	}
 65→
 66→	for _, spec := range loadOrder {
 67→		data, err := readFixtureFile(dataFS, spec)
 68→		if err != nil {
 69→			return err
 70→		}
 71→		if data == nil {
 72→			continue // file not found — skip
 73→		}
 74→
 75→		if err := loadTable(ctx, pool, spec, data, colTypes); err != nil {
 76→			return err
 77→		}
 78→	}
 79→
 80→	// Refresh materialized views.
 81→	for _, view := range materializedViews {
 82→		if _, err := pool.Exec(ctx, "REFRESH MATERIALIZED VIEW "+view); err != nil {
 83→			return fmt.Errorf("fixture: refresh %s: %w", view, err)
 84→		}
 85→	}
 86→
 87→	return nil
 88→}
 89→
 90→// LoadOrder returns the FK-safe table loading order. Useful for tests.
 91→func LoadOrder() []string {
 92→	names := make([]string, len(loadOrder))
 93→	for i, spec := range loadOrder {
 94→		names[i] = spec.Schema + "." + spec.Table
 95→	}
 96→	return names
 97→}
 98→
 99→// readFixtureFile reads and decompresses a fixture file from the FS.
100→// Returns nil if the file does not exist.
101→func readFixtureFile(dataFS fs.FS, spec tableSpec) ([]byte, error) {
102→	filename := fmt.Sprintf("%s.%s.json", spec.Schema, spec.Table)
103→	xzFilename := filename + ".xz"
104→
105→	// Try xz-compressed first.
106→	if data, err := fs.ReadFile(dataFS, xzFilename); err == nil {
107→		decompressed, err := xzDecompress(data)
108→		if err != nil {
109→			return nil, fmt.Errorf("fixture: decompress %s: %w", xzFilename, err)
110→		}
111→		return decompressed, nil
112→	}
113→
114→	// Try uncompressed.
115→	data, err := fs.ReadFile(dataFS, filename)
116→	if err != nil {
117→		return nil, nil //nolint:nilerr // file not found is not an error
118→	}
119→	return data, nil
120→}
121→
122→// xzDecompress decompresses xz data using the xz command-line tool.
123→func xzDecompress(data []byte) ([]byte, error) {
124→	cmd := exec.Command("xz", "-dc") //nolint:gosec // G204: xz is a trusted system tool
125→	cmd.Stdin = bytes.NewReader(data)
126→	out, err := cmd.Output()
127→	if err != nil {
128→		return nil, fmt.Errorf("xz: %w", err)
129→	}
130→	return out, nil
131→}
132→
133→// columnInfo holds type metadata for a single column.
134→type columnInfo struct {
135→	UDTName  string // e.g. "geometry", "geography", "jsonb", "text"
136→	DataType string // e.g. "USER-DEFINED", "jsonb", "text"
137→}
138→
139→// discoverColumnTypes queries information_schema to build a map of
140→// schema.table.column → columnInfo for all fixture tables.
141→func discoverColumnTypes(ctx context.Context, pool *pgxpool.Pool) (map[string]columnInfo, error) {
142→	result := make(map[string]columnInfo)
143→
144→	// Build list of schemas and tables to query.
145→	schemas := make(map[string]bool)
146→	for _, spec := range loadOrder {
147→		schemas[spec.Schema] = true
148→	}
149→
150→	for schema := range schemas {
151→		rows, err := pool.Query(ctx,
152→			`SELECT table_name, column_name, data_type, udt_name
153→			 FROM information_schema.columns
154→			 WHERE table_schema = $1
155→			 ORDER BY table_name, ordinal_position`, schema)
156→		if err != nil {
157→			return nil, fmt.Errorf("fixture: discover columns for %s: %w", schema, err)
158→		}
159→
160→		for rows.Next() {
161→			var tableName, colName, dataType, udtName string
162→			if err := rows.Scan(&tableName, &colName, &dataType, &udtName); err != nil {
163→				rows.Close()
164→				return nil, fmt.Errorf("fixture: scan column info: %w", err)
165→			}
166→			key := fmt.Sprintf("%s.%s.%s", schema, tableName, colName)
167→			result[key] = columnInfo{UDTName: udtName, DataType: dataType}
168→		}
169→		rows.Close()
170→		if err := rows.Err(); err != nil {
171→			return nil, fmt.Errorf("fixture: iterate columns for %s: %w", schema, err)
172→		}
173→	}
174→
175→	return result, nil
176→}
177→
178→// loadTable parses JSON data and inserts rows into the target table.
179→func loadTable(ctx context.Context, pool *pgxpool.Pool, spec tableSpec, data []byte, colTypes map[string]columnInfo) error {
180→	var rows []map[string]any
181→	if err := json.Unmarshal(data, &rows); err != nil {
182→		return fmt.Errorf("fixture: parse %s.%s: %w", spec.Schema, spec.Table, err)
183→	}
184→	if len(rows) == 0 {
185→		return nil
186→	}
187→
188→	qualifiedName := fmt.Sprintf("%s.%s", spec.Schema, spec.Table)
189→
190→	// Extract column order from the first row.
191→	columns := orderedKeys(rows[0])
192→
193→	// Check if any columns need special handling (geometry).
194→	hasGeo := false
195→	geoColumns := make(map[string]bool)
196→	for _, col := range columns {
197→		key := fmt.Sprintf("%s.%s.%s", spec.Schema, spec.Table, col)
198→		info, ok := colTypes[key]
199→		if ok && (info.UDTName == "geometry" || info.UDTName == "geography") {
200→			geoColumns[col] = true
201→			hasGeo = true
202→		}
203→	}
204→
205→	if hasGeo {
206→		return loadTableWithGeo(ctx, pool, qualifiedName, columns, rows, geoColumns)
207→	}
208→	return loadTableDirect(ctx, pool, qualifiedName, columns, rows, colTypes, spec)
209→}
210→
211→// loadTableDirect loads data using pgx CopyFrom for tables without geometry.
212→func loadTableDirect(ctx context.Context, pool *pgxpool.Pool, qualifiedName string, columns []string, rows []map[string]any, colTypes map[string]columnInfo, spec tableSpec) error {
213→	// Build JSONB column set for proper marshaling.
214→	jsonbCols := make(map[string]bool)
215→	for _, col := range columns {
216→		key := fmt.Sprintf("%s.%s.%s", spec.Schema, spec.Table, col)
217→		info, ok := colTypes[key]
218→		if ok && info.UDTName == "jsonb" {
219→			jsonbCols[col] = true
220→		}
221→	}
222→
223→	copyRows := make([][]any, len(rows))
224→	for i, row := range rows {
225→		vals := make([]any, len(columns))
226→		for j, col := range columns {
227→			vals[j] = convertValue(row[col], jsonbCols[col])
228→		}
229→		copyRows[i] = vals
230→	}
231→
232→	parts := strings.SplitN(qualifiedName, ".", 2)
233→	copyCount, err := pool.CopyFrom(ctx,
234→		pgx.Identifier{parts[0], parts[1]},
235→		columns,
236→		pgx.CopyFromRows(copyRows),
237→	)
238→	if err != nil {
239→		return fmt.Errorf("fixture: copy %s: %w", qualifiedName, err)
240→	}
241→	if int(copyCount) != len(rows) {
242→		return fmt.Errorf("fixture: copy %s: expected %d rows, got %d", qualifiedName, len(rows), copyCount)
243→	}
244→
245→	return nil
246→}
247→
248→// loadTableWithGeo loads data using a staging table for geometry columns.
249→// Geometry values are stored as GeoJSON text in the JSON fixture, so we
250→// load into a temp table with text columns, then INSERT with ST_GeomFromGeoJSON.
251→func loadTableWithGeo(ctx context.Context, pool *pgxpool.Pool, qualifiedName string, columns []string, rows []map[string]any, geoColumns map[string]bool) error {
252→	tx, err := pool.Begin(ctx)
253→	if err != nil {
254→		return fmt.Errorf("fixture: begin tx for %s: %w", qualifiedName, err)
255→	}
256→	defer tx.Rollback(ctx) //nolint:errcheck
257→
258→	// Create temp table mimicking the target but with text for geo columns.
259→	tempName := "fixture_staging"
260→	createCols := make([]string, len(columns))
261→	for i, col := range columns {
262→		// All columns are text in the staging table — geo columns get
263→		// converted to geometry via ST_GeomFromGeoJSON in the final INSERT.
264→		createCols[i] = fmt.Sprintf("%s text", col)
265→	}
266→
267→	dropSQL := fmt.Sprintf("DROP TABLE IF EXISTS %s", tempName)
268→	if _, err := tx.Exec(ctx, dropSQL); err != nil {
269→		return fmt.Errorf("fixture: drop staging: %w", err)
270→	}
271→
272→	createSQL := fmt.Sprintf("CREATE TEMP TABLE %s (%s)", tempName, strings.Join(createCols, ", "))
273→	if _, err := tx.Exec(ctx, createSQL); err != nil {
274→		return fmt.Errorf("fixture: create staging for %s: %w", qualifiedName, err)
275→	}
276→
277→	// COPY into staging table with all values as text.
278→	copyRows := make([][]any, len(rows))
279→	for i, row := range rows {
280→		vals := make([]any, len(columns))
281→		for j, col := range columns {
282→			v := row[col]
283→			switch {
284→			case v == nil:
285→				vals[j] = nil
286→			case geoColumns[col]:
287→				// GeoJSON object → JSON string
288→				b, err := json.Marshal(v)
289→				if err != nil {
290→					return fmt.Errorf("fixture: marshal geo %s row %d: %w", col, i, err)
291→				}
292→				vals[j] = string(b)
293→			default:
294→				vals[j] = toText(v)
295→			}
296→		}
297→		copyRows[i] = vals
298→	}
299→
300→	_, err = tx.CopyFrom(ctx,
301→		pgx.Identifier{tempName},
302→		columns,
303→		pgx.CopyFromRows(copyRows),
304→	)
305→	if err != nil {
306→		return fmt.Errorf("fixture: copy staging %s: %w", qualifiedName, err)
307→	}
308→
309→	// Build INSERT from staging with ST_GeomFromGeoJSON for geo columns.
310→	selectCols := make([]string, len(columns))
311→	for i, col := range columns {
312→		if geoColumns[col] {
313→			selectCols[i] = fmt.Sprintf("ST_GeomFromGeoJSON(%s) AS %s", col, col)
314→		} else {
315→			// Cast text back to original column types.
316→			selectCols[i] = col
317→		}
318→	}
319→
320→	insertSQL := fmt.Sprintf(
321→		"INSERT INTO %s (%s) SELECT %s FROM %s",
322→		qualifiedName,
323→		strings.Join(columns, ", "),
324→		strings.Join(selectCols, ", "),
325→		tempName,
326→	)
327→	if _, err := tx.Exec(ctx, insertSQL); err != nil {
328→		return fmt.Errorf("fixture: insert %s from staging: %w", qualifiedName, err)
329→	}
330→
331→	if _, err := tx.Exec(ctx, dropSQL); err != nil {
332→		return fmt.Errorf("fixture: cleanup staging: %w", err)
333→	}
334→
335→	if err := tx.Commit(ctx); err != nil {
336→		return fmt.Errorf("fixture: commit %s: %w", qualifiedName, err)
337→	}
338→
339→	return nil
340→}
341→
342→// toText converts a JSON-decoded value to its text representation for the
343→// staging table. All staging columns are text, so every value must be a string.
344→func toText(v any) string {
345→	switch vt := v.(type) {
346→	case string:
347→		return vt
348→	case float64:
349→		return fmt.Sprintf("%v", vt)
350→	case bool:
351→		if vt {
352→			return "true"
353→		}
354→		return "false"
355→	default:
356→		b, err := json.Marshal(v)
357→		if err != nil {
358→			return fmt.Sprintf("%v", v)
359→		}
360→		return string(b)
361→	}
362→}
363→
364→// convertValue converts a JSON-decoded value to a pgx-compatible type.
365→func convertValue(v any, isJSONB bool) any {
366→	if v == nil {
367→		return nil
368→	}
369→	if isJSONB {
370→		// JSONB columns: marshal the value back to a JSON byte slice
371→		// which pgx will send as JSONB.
372→		switch vt := v.(type) {
373→		case map[string]any, []any:
374→			b, err := json.Marshal(vt)
375→			if err != nil {
376→				return nil
377→			}
378→			return b
379→		case string:
380→			return []byte(vt)
381→		default:
382→			b, err := json.Marshal(v)
383→			if err != nil {
384→				return nil
385→			}
386→			return b
387→		}
388→	}
389→	return v
390→}
391→
392→// orderedKeys returns the keys of a map in a stable order.
393→// JSON object key order is not guaranteed, so we sort alphabetically.
394→// However, for fixture loading the order doesn't matter as long as it's
395→// consistent between the column list and the data rows.
396→func orderedKeys(m map[string]any) []string {
397→	keys := make([]string, 0, len(m))
398→	for k := range m {
399→		keys = append(keys, k)
400→	}
401→	// Sort for determinism.
402→	sortStrings(keys)
403→	return keys
404→}
405→
406→// sortStrings sorts a string slice in place (insertion sort — fine for small slices).
407→func sortStrings(s []string) {
408→	for i := 1; i < len(s); i++ {
409→		for j := i; j > 0 && s[j] < s[j-1]; j-- {
410→			s[j], s[j-1] = s[j-1], s[j]
411→		}
412→	}
413→}
414→
415→// WriteJSON writes table data as JSON files to the given writer function.
416→// This is used by the fixtureutil CLI to generate JSON from database queries.
417→func WriteJSON(w io.Writer, rows []map[string]any) error {
418→	enc := json.NewEncoder(w)
419→	enc.SetIndent("", "  ")
420→	return enc.Encode(rows)
421→}
