 81→			if err != nil {
 82→				fmt.Fprintf(os.Stderr, "error: create output file: %v\n", err)
 83→				os.Exit(1)
 84→			}
 85→			defer w.Close()
 86→		} else {
 87→			w = os.Stdout
 88→		}
